void solve(){
    int n;
    cin >> n;
    if(n == 1){
        cout << 1 << endl;
        return;
    }
    deque<int>d;
    d.push_back(n);
    d.push_front(1);
    vector<int>vis(n + 1 , 0);
    vis[n]= 1, vis[1]  = 1;
    while(true){
        int r = d.back();
        int l = d.front();
        bool ll = false, rr = false;
        if(r > l){
            r--;
            l++;
            if(!vis[r]){
                d.push_front(r);
                rr = true;
                vis[r] = 1;
            }
            if(!vis[l]){
                ll = true;
                d.push_back(l);
                vis[l] = 1;
            }
        }
        else{
            r++;
            l--;
            if(!vis[r]){
                rr = true;
                d.push_front(r);
                vis[r] = 1;
            }
            if(!vis[l]){
                ll = true;
                d.push_back(l);
                vis[l] = 1;
            }
        }
        if(!ll && !rr){
            break;
        }
    }
    int s = 0, pp = d.front();
    for(int &e : d){
        s += abs(e - pp);
        pp = e;
    }
    cout << s << endl;
}
